public class Member {
    private final String name;
    public Member(String name) { this.name = name; }
    public String getName() { return name; }
}

public class Process {
    public static void display(String payload) {
        if (payload != null) {
            System.out.println(payload.trim());
        }
    }
}

examples.toCode:
struct Process {
    static func display(_ payload: String?) {
        guard let actualPayload = payload else { return }
        print(actualPayload.trimmingCharacters(in: .whitespaces))
    }
}
